import { ref } from 'vue'
import { ElMessage } from 'element-plus'
import profile from '@/api/profile'

export function useProfileData() {
  const loading = ref(false)
  const basicInfo = ref({})
  const profileData = ref({})
  const completionData = ref({})

  // 获取基本信息
  const fetchBasicInfo = async () => {
    try {
      loading.value = true
      const response = await profile.getBasicInfo()
      if (response.data?.code === 200) {
        basicInfo.value = response.data.data || {}
      }
    } catch (error) {
      console.error('获取基本信息失败:', error)
      ElMessage.error('获取基本信息失败，请稍后重试')
    } finally {
      loading.value = false
    }
  }

  // 获取模块数据
  const fetchModuleData = async (moduleType) => {
    try {
      loading.value = true
      let data = null

      switch (moduleType) {
        case 'job_intention':
          const jobRes = await profile.jobIntention.get()
          data = jobRes.data?.data
          break
        case 'work_experience':
          const workRes = await profile.workExperience.get()
          data = workRes.data?.data
          break
        // ... 其他模块类型
      }

      return data
    } catch (error) {
      console.error(`获取${moduleType}数据失败:`, error)
      ElMessage.error('获取数据失败，请稍后重试')
      return null
    } finally {
      loading.value = false
    }
  }

  // 获取完整度数据
  const fetchCompletionData = async () => {
    try {
      loading.value = true
      const response = await profile.getCompleteness()
      if (response.data?.code === 200) {
        completionData.value = response.data.data || {}
      }
    } catch (error) {
      console.error('获取完整度数据失败:', error)
      ElMessage.error('获取完整度数据失败，请稍后重试')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    basicInfo,
    profileData,
    completionData,
    fetchBasicInfo,
    fetchModuleData,
    fetchCompletionData
  }
}
